def extract_tags_from_matroska(file_path):
    """Extract tags from a Matroska file using mkvextract."""
    # Level-1: task-start message — use empty prefix for now
    log_processing("Extracting tags from video file", indent=1, prefix="")
    
    try:
        result = subprocess.run(
            ["mkvextract", "tags", str(file_path)],
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True
        )
        
        log_debug(f"mkvextract return code: {result.returncode}", indent=2)
        if result.stderr:
            log_debug(f"mkvextract stderr: {result.stderr}", indent=2)
            
        if result.returncode == 0 and result.stdout:
            log_success("Tags extracted successfully", indent=2)
            return result.stdout
        else:
            log_error(f"mkvextract failed with return code {result.returncode}", indent=2)
            return None
            
    except FileNotFoundError:
        log_error("mkvextract not found. Please install mkvtoolnix.", indent=2)
        sys.exit(1)
    except Exception as e:
        log_debug(f"Exception in extract_tags_from_matroska: {e}", indent=2)
        return None

def parse_matroska_tags(xml_content):
    """Parse the XML tags from mkvextract output - only global tags (no Targets)."""
    # Level-1: task-start message — use empty prefix
    log_processing("Parsing extracted tags", indent=1, prefix="")
    
    if not xml_content or not xml_content.strip():
        log_warning("No XML content to parse", indent=2)
        return {}
    
    try:
        root = ET.fromstring(xml_content)
        tags = {}
        
        # Look for global tags only (without Targets or with empty Targets)
        for tag in root.findall('Tag'):
            targets = tag.find('Targets')
            # Skip tags that have TrackUID (stream-specific tags)
            if targets is not None:
                track_uid = targets.find('TrackUID')
                if track_uid is not None:
                    continue  # Skip stream-specific tags
            
            # Process global tags
            for simple in tag.findall('Simple'):
                name_elem = simple.find('Name')
                string_elem = simple.find('String')
                if name_elem is not None and string_elem is not None:
                    tag_name = name_elem.text
                    tag_value = string_elem.text
                    
                    # Skip ENCODER tag - we don't want it in the NFO
                    if tag_name != 'ENCODER':
                        tags[tag_name] = tag_value
                    else:
                        log_debug("Skipped ENCODER tag", indent=2)
        
        if tags:
            log_success(f"Found {len(tags)} relevant tags: {list(tags.keys())}", indent=2)
        else:
            log_warning("No relevant tags found", indent=2)
        
        return tags
        
    except ET.ParseError as e:
        log_error(f"Error parsing XML tags: {e}", indent=2)
        return {}

def create_jellyfin_nfo(tags):
    """Create Jellyfin NFO XML from extracted tags - only include existing tags."""
    # Level-1: task-start message �� use empty prefix
    log_processing("Creating Jellyfin NFO structure", indent=1, prefix="")
    
    root = ET.Element('musicvideo')
    
    # Tag mapping: Matroska tag -> Jellyfin field (ENCODER removed)
    tag_mapping = {
        'TITLE': 'title',
        'ARTIST': 'artist', 
        'DATE_RELEASED': 'releasedate',
        'DESCRIPTION': 'description',  # Custom field
        'COMMENT': 'comment'  # Custom field
    }
    
    # Always include these basic fields
    lockdata = ET.SubElement(root, 'lockdata')
    lockdata.text = 'false'
    
    dateadded = ET.SubElement(root, 'dateadded')
    dateadded.text = datetime.datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    
    # Only add tags that actually exist in the video file
    added_tags = []
    for matroska_tag, jellyfin_field in tag_mapping.items():
        if matroska_tag in tags:
            elem = ET.SubElement(root, jellyfin_field)
            value = tags[matroska_tag]
            
            # Clean up artist name (remove @ if present)
            if jellyfin_field == 'artist' and value.startswith('@'):
                value = value[1:]
                
            elem.text = value
            added_tags.append(jellyfin_field)
    
    if added_tags:
        log_success(f"Added NFO fields: {added_tags}", indent=2)
    else:
        log_warning("No metadata fields added to NFO", indent=2)
    
    return root

def format_xml_output(root):
    """Format XML with proper indentation."""
    def indent(elem, level=0):
        i = "\n" + level * "  "
        if len(elem):
            if not elem.text or not elem.text.strip():
                elem.text = i + "  "
            if not elem.tail or not elem.tail.strip():
                elem.tail = i
            for elem in elem:
                indent(elem, level + 1)
            if not elem.tail or not elem.tail.strip():
                elem.tail = i
        else:
            if level and (not elem.tail or not elem.tail.strip()):
                elem.tail = i
    
    indent(root)
    return ET.tostring(root, encoding='unicode')

def validate_xml(nfo_path):
    """Validate the generated NFO XML file using Python's built-in XML parser."""
    # Level-1: task-start message — use empty prefix
    log_processing(f"Validating XML: {Fore.CYAN}{nfo_path.name}{Style.RESET_ALL}", indent=1, prefix="")
    
    try:
        # Parse the XML file to check for well-formedness
        with open(nfo_path, 'r', encoding='utf-8') as f:
            xml_content = f.read()
        
        # Try to parse it
        root = ET.fromstring(xml_content)
        
        # Basic structure validation for musicvideo NFO
        if root.tag != 'musicvideo':
            log_error(f"Root element should be 'musicvideo', found '{root.tag}'", indent=2)
            return False
        
        # Check for required elements
        required_elements = ['lockdata', 'dateadded']
        for req_elem in required_elements:
            if root.find(req_elem) is None:
                log_error(f"Missing required element: {req_elem}", indent=2)
                return False
        
        # Count elements for info
        element_count = len(list(root))
        elements = [elem.tag for elem in root]
        
        log_success(f"XML is well-formed with {element_count} elements", indent=2)
        log_info(f"Elements: {elements}", indent=2)
        
        return True
        
    except ET.ParseError as e:
        log_error(f"XML parse error: {e}", indent=2)
        return False
    except FileNotFoundError:
        log_error(f"File not found: {nfo_path}", indent=2)
        return False
    except Exception as e:
        log_error(f"Validation error: {e}", indent=2)
        return False

def process_matroska_files():
    """Process all Matroska files in the current directory."""
    # Common Matroska file extensions
    matroska_extensions = ['.mkv', '.webm', '.mka']
    
    current_dir = Path('.')
    processed_count = 0
    
    for file_path in current_dir.iterdir():
        if file_path.is_file() and file_path.suffix.lower() in matroska_extensions:
            print()  # blank line between files
            # Level-0 file message: keep the 'Processing:' label in yellow
            log_processing(f"{Fore.CYAN}{file_path.name}{Style.RESET_ALL}", indent=0, prefix="Processing:")
            
            # Extract tags
            xml_content = extract_tags_from_matroska(file_path)
            if xml_content is None:
                log_error("Skipping file - could not extract tags", indent=1)
                continue
            
            # Parse tags (only global tags, not stream-specific, excluding ENCODER)
            tags = parse_matroska_tags(xml_content)
            if not tags:
                log_warning("Skipping file - no relevant tags found", indent=1)
                continue
            
            # Create NFO - only with existing tags
            nfo_root = create_jellyfin_nfo(tags)
            
            # Write NFO file (level-1 task-start message, no prefix)
            nfo_path = file_path.with_suffix('.nfo')
            log_processing(f"Writing NFO file: {Fore.CYAN}{nfo_path.name}{Style.RESET_ALL}", indent=1, prefix="")
            
            try:
                with open(nfo_path, 'w', encoding='utf-8') as f:
                    f.write('<?xml version="1.0" encoding="utf-8" standalone="yes"?>\n')
                    f.write(format_xml_output(nfo_root))
                
                log_success(f"Created NFO file successfully", indent=2)
                
                # Validate the generated XML using Python's built-in parser
                is_valid = validate_xml(nfo_path)
                if not is_valid:
                    log_error("XML validation failed", indent=2)
                
                processed_count += 1
                
            except Exception as e:
                log_error(f"Could not write NFO file: {e}", indent=1)
    
    print(f"\n{Fore.GREEN}Completed:{Style.RESET_ALL} Processed {processed_count} files.")

if __name__ == "__main__":
    print(f"{Fore.CYAN}Matroska to Jellyfin NFO Converter{Style.RESET_ALL}")
    print("=" * 35)
    process_matroska_files()